---@class LDefenceWarSkill
local LDefenceWarSkill = LxClass("LDefenceWarSkill", nil)

local CS               = CS
local Tweening         = DG.Tweening
local Ease             = CS.YXTweeningEase
local table            = table
local ipairs           = ipairs
local pairs            = pairs


local typeofParticleSystem = typeof(UnityEngine.ParticleSystem)
local typeofAnimator = typeof(UnityEngine.Animator)

function LDefenceWarSkill:LDefenceWarSkill(obj)
    self._obj     = obj
    self._ctrl    = obj:GetCtrl()
    self._mgr     = self._ctrl:GetMgr()
    self._objCtrl = self._mgr:GetCtrl("Objs")
end

-- 销毁
function LDefenceWarSkill:Destroy()
    for i, v in ipairs(self._skillObjList) do
        CS.Destroy(v.obj)
    end
    self._skillObjList = {}

    table.removeall(self)
    self._isDestroy = true
end

-- 销毁
function LDefenceWarSkill:IsDestroy()
    return self._isDestroy
end

-- 初始化
function LDefenceWarSkill:Init(skillId, skillLev)
    self._skillId       = skillId
    self._skillLev      = skillLev

    -- 技能播放时间
    self._skillPlayTime = 0

    -- 技能对象列表
    self._skillObjList  = {}

    -- 增加的属性
    self._addAttrList   = {}

    self._effPoolCtrl   = self._ctrl:GetCtrl("EffPool")

    self:InitSkillRefData()
    -- self:Preload()
end

-- 初始化技能配置相关数据
function LDefenceWarSkill:InitSkillRefData()
    local skillRef = gModelDefenceWar:GetSkillRef(self._skillId, self._skillLev)
    self._skillRef = skillRef
    self._effName = skillRef.hitEffect

    self._skillInitCd = skillRef.CD / 1000
    self._skillCd = self._skillCd or self._skillInitCd

    self._activeSkill = skillRef.type == 1
    self._isMySelf = skillRef.skillType == 1

    -- 目标数
    self._skillNum = skillRef.skillNum

    -- 持续时间
    self._durationTime = skillRef.skillTime / 1000
    self._endTime = 0

    -- 技能播放时间
    self._skillPlayTime = self._durationTime == 0 and 3 or self._durationTime

    -- 持续伤害间隔
    self._durationHurtInterval = skillRef.skillInterval or 0

    -- 缩放
    self._scale = skillRef.hitEffectScale

    -- buff数据
    self._buffData = {}

    if self:IsBuffSkill() then
        local list = string.split(skillRef.buff, ",")

        self._buffData.attrName = list[1]
        self._buffData.attrType = tonumber(list[2])
        self._buffData.attrValue = tonumber(list[3])
    end
end

-- 预加载技能资源
function LDefenceWarSkill:Preload()
    self._effPoolCtrl:LoadEffObj(self._effName)
end

-- 获取对象
function LDefenceWarSkill:GetObj()
    return self._obj
end

-- 获取技能id
function LDefenceWarSkill:GetSkillId()
    return self._skillId
end

-- 获取技能等级
function LDefenceWarSkill:GetSkillLev()
    return self._skillLev
end

-- 设置技能等级
function LDefenceWarSkill:SetSkillLev(lev)
    self._skillLev = lev

    self:InitSkillRefData()
end

-- 获取技能配置
function LDefenceWarSkill:GetSkillRef()
    return self._skillRef
end

-- ture:表示主动技能
function LDefenceWarSkill:IsActiveSkill()
    return self._activeSkill
end

-- true:表示buff技能
function LDefenceWarSkill:IsBuffSkill()
    return not self._activeSkill
end

-- 持续伤害技能
function LDefenceWarSkill:IsDurationHurtSkill()
    return self._durationHurtInterval > 0
end

-- true:技能作用于我方
function LDefenceWarSkill:IsMySide()
    return self._isMySelf
end

-- 获取英雄等级配置
function LDefenceWarSkill:GetHeroLevRef()
    return self._heroLevRef
end

-- update
function LDefenceWarSkill:Update(dt, monsterInSkillRange)
    if self._loadingRes then
        return true
    end

    for i, v in ipairs(self._skillObjList) do
        v.endTime = v.endTime - dt
        if v.endTime <= 0 then
            CS.Destroy(v.obj)
            table.remove(self._skillObjList, i)
            break
        end
    end

    if self._endTime > 0 then
        self._endTime = self._endTime - dt
        if self._endTime <= 0 then
            self._endTime = 0
            if self:IsBuffSkill() then
                self:EndBuffSkill()
            end
        end
    end

    if self._nextHurtTime then
        self._nextHurtTime = self._nextHurtTime - dt
        if self._nextHurtTime <= 0 then
            self._nextHurtTime = 0
            self:DoDurationHurtSkill()
        end
    end

    self._skillCd = self._skillCd - dt
    if self._skillCd <= 0 then
        if monsterInSkillRange then
            self._skillCd = self._skillInitCd

            if self:IsActiveSkill() then
                self:DoActiveSkill()
            else
                self:DoBuffSkill()
            end
            return true
        end
    end
    return false
end

-- 释放主动技能
function LDefenceWarSkill:DoActiveSkill()
    local skillRef = self:GetSkillRef()
    gLGameAudio:PlaySound(skillRef.attackSound)

    local pos, targetList = nil, nil

    if skillRef.skillrange > 0 then
        pos, targetList = self._objCtrl:GetDoSkillPosAndTargetList(self:GetSkillRef())
        self:DoRangeSkill(pos)
    else
        targetList = self._objCtrl:GetSingleSkillTargetList(self._skillNum)
        self:DoSingleSkill(targetList, skillRef.hitEffect)
    end

    self._mgr:CalcSkillHurtTargetList(self, targetList)
    if self:IsDurationHurtSkill() and pos then
        self._skillPos = pos
        self._nextHurtTime = self._durationHurtInterval
    end

    self:SendUseSkillEvent()
end

-- 单体技能
function LDefenceWarSkill:DoSingleSkill(targetList, effName)
    for i, obj in ipairs(targetList) do   
        obj:PlayHitEffect(effName, self._scale)
    end
end

-- 范围技能
function LDefenceWarSkill:DoRangeSkill(pos)
    self._loadingRes = true
    self._effPoolCtrl:LoadEffObj(self._effName, function(originObj)
        if self:IsDestroy() then
            return
        end

        local obj = CS.InstantObject(originObj)
        local trans = obj.transform
        trans.localPosition = pos
        trans.localScale = Vector3(self._scale, self._scale, self._scale)
        local parent = self._effPoolCtrl:GetNodeParent()
        trans:SetParent(parent, false)

        table.insert(self._skillObjList, { obj = obj, trans = trans, endTime = self._skillPlayTime })

        self._loadingRes = nil
    end)
end

-- 释放持续伤害
function LDefenceWarSkill:DoDurationHurtSkill()
    local targetList = self._objCtrl:GetDoSkillDamageTargetList(self:GetSkillRef(), self._skillPos)

    self._nextHurtTime = self._durationHurtInterval

    if #targetList == 0 then
        return
    end

    self._mgr:CalcSkillHurtTargetList(self, targetList)
end

-- 释放buff技能
function LDefenceWarSkill:DoBuffSkill()
    if self:IsMySide() then
        -- 给我方加buff
        local hoerId = self._obj:GetHeroId()
        local skillId = self:GetSkillId()
        local skillLev = self:GetSkillLev()
        local tab = self._buffData
        self._ctrl:AddBuff(hoerId, skillId, skillLev, tab.attrName, tab.attrType, tab.attrValue, self._skillNum)
    else
        -- 给敌方加buff
        local pos, targetList = self._objCtrl:GetDoSkillPosAndTargetList(self:GetSkillRef())
        local tab             = {}
        tab.heroId            = self._obj:GetHeroId()
        tab.skillId           = self:GetSkillId()
        tab.skillLev          = self:GetSkillLev()
        tab.attrName          = self._buffData.attrName
        tab.attrType          = self._buffData.attrType
        tab.attrValue         = self._buffData.attrValue
        tab.pos               = pos
        tab.targetList        = targetList
        self._objCtrl:AddBuff(tab)
    end

    self._endTime = self._durationTime
    self:SendUseSkillEvent()
end

-- 结束 buff 技能
function LDefenceWarSkill:EndBuffSkill()
    local hoerId = self._obj:GetHeroId()
    local skillId = self:GetSkillId()

    if self:IsMySide() then
        self._ctrl:RemoveBuff(hoerId, skillId)
    else
        self._objCtrl:RemoveBuff(hoerId, skillId)
    end
end

-- 发送使用技能事件
function LDefenceWarSkill:SendUseSkillEvent()
    local heroId = self._obj:GetHeroId()
    local skillId = self:GetSkillId()
    local skillLev = self:GetSkillLev()

    local heorRef = gModelDefenceWar:GetHeroRef(heroId)
    local isBaseSkill = heorRef.startSkill == skillId

    FireEvent(EventNames.DEFENCEWAR_USE_SKILL,
    { heroId = heroId, skillId = skillId, skillLev = skillLev, isBaseSkill = isBaseSkill })
end

-- 获取技能持续时间
function LDefenceWarSkill:GetDuration()
    return self._durationTime
end

-- 获取技能结束时间
function LDefenceWarSkill:GetEndTime()
    return self._endTime
end

-- 获取攻击
function LDefenceWarSkill:GetAtk()
    local atk = self._obj:GetAtk()
    local skillRef = self:GetSkillRef()

    return atk * skillRef.skilldamage
end

-- true: 技能cd中
function LDefenceWarSkill:IsSkillCd()
    return self._skillCd > 0
end

-- 获取技能cd
function LDefenceWarSkill:GetSkillCd()
    return self._skillCd
end

-- 获取技能初始化cd
function LDefenceWarSkill:GetSkillInitCd()
    return self._skillInitCd
end

-- 暂停
function LDefenceWarSkill:OnPauseGame()
    self:UpdateAnimatorSpeed(0)
end

-- 恢复
function LDefenceWarSkill:OnResumeGame()
    local speed = self._obj:GetCtrl():GetMgr():GetTimeScale()
    self:UpdateAnimatorSpeed(speed)
end

-- 设置技能速度
function LDefenceWarSkill:UpdateAnimatorSpeed(speed)
    for i, v in ipairs(self._skillObjList) do
        local trans = v.trans

        local animatorList = self:GetAnimatorList(trans) or {}
        local animatorLen = #animatorList
        for k = 1, animatorLen do
            local animator = animatorList[k]
            animator.speed = speed
        end

        local particleSystemList = self:GetParticleSystemList(trans) or {}
        local particleSystemLen = #particleSystemList
        for k = 1, particleSystemLen do
            local particleSystem = particleSystemList[k]
            local mainModule = particleSystem.main
            if mainModule then
                mainModule.simulationSpeed = speed
            end
        end
    end
end

-- 获取所有动画
function LDefenceWarSkill:GetAnimatorList(trans)
    self._animatorList = self._animatorList or {}
    if not self._animatorList[trans] then
        local cList = trans:GetComponentsInChildren(typeofAnimator, true)
        self._animatorList[trans] = cList:ToTable()
    end
    return self._animatorList[trans]
end

-- 获取所有粒子
function LDefenceWarSkill:GetParticleSystemList(trans)
    self._particleSystemList = self._particleSystemList or {}
    if not self._particleSystemList[trans] then
        local cList = trans:GetComponentsInChildren(typeofParticleSystem, true)
        self._particleSystemList[trans] = cList:ToTable()
    end
    return self._particleSystemList[trans]
end

return LDefenceWarSkill
